/* v4.0.0 | Premium solid tokens, zero gradient, zero native select */
import { useState, useMemo } from 'react';
import { useFirebaseData } from '../../shared/services/firebase';
import { auth } from '../../shared/services/auth';
import { formatCurrency, computeSnapshot, sortByNewest, getCurrentMonthKey } from '../../shared/services/finance';
import {
  LogOut, Wallet, Receipt, QrCode, MessageCircle,
  Home, ChartNoAxesColumnIncreasing, UserRound, UsersRound,
  ArrowDownCircle, ArrowUpCircle, Search, UserPlus, Tag
} from 'lucide-react';
import { Sheet } from '../../shared/components/ui/Sheet';
import { PremiumDropdown } from '../../shared/components/ui/PremiumDropdown';
import type { Transaction, UserDoc } from '../../shared/types';
import { doc, updateDoc } from 'firebase/firestore';
import { db, writeLog, addPaymentRequestToDb, usePaymentRequests, useAppSetting } from '../../shared/services/firebase';
import { sendNotification } from '../../shared/services/notifier';

type Props = { userDoc: UserDoc; };
type WargaTab = 'home' | 'transparency' | 'profile' | 'add_link';
type DateFilter = 'today' | 'month' | 'year' | 'all';

const DATE_FILTERS: { value: DateFilter; label: string }[] = [
  { value: 'today', label: 'Hari' },
  { value: 'month', label: 'Bulan' },
  { value: 'year', label: 'Tahun' },
  { value: 'all', label: 'Semua' },
];

const PAYMENT_METHODS: { value: 'qris' | 'tunai'; label: string; meta: string }[] = [
  { value: 'qris', label: 'QRIS', meta: 'Scan kode QR di aplikasi dompet digital' },
  { value: 'tunai', label: 'Tunai', meta: 'Bayar langsung ke petugas kas' },
];

function getDateKey(date: string) {
  const value = new Date(date);
  if (Number.isNaN(value.getTime())) return '';
  return value.toISOString().slice(0, 10);
}

function filterTransactions(items: Transaction[], filter: DateFilter) {
  const today = new Date();
  const todayKey = today.toISOString().slice(0, 10);
  const monthKey = today.toISOString().slice(0, 7);
  const yearKey = today.toISOString().slice(0, 4);
  return items.filter((item) => {
    const dateKey = getDateKey(item.date);
    if (filter === 'today') return dateKey === todayKey;
    if (filter === 'month') return dateKey.slice(0, 7) === monthKey;
    if (filter === 'year') return dateKey.slice(0, 4) === yearKey;
    return true;
  });
}

export default function WargaApp({ userDoc }: Props) {
  const { members, transactions, loading } = useFirebaseData();
  const { requests } = usePaymentRequests();
  const [activeTab, setActiveTab] = useState<WargaTab>('home');
  const [filter, setFilter] = useState<DateFilter>('month');
  const [paySheetOpen, setPaySheetOpen] = useState(false);
  const [payMethod, setPayMethod] = useState<'qris' | 'tunai' | null>(null);
  const [payType, setPayType] = useState<'bulanan' | 'tahunan'>('bulanan');
  const [searchQuery, setSearchQuery] = useState('');
  const [sendingReq, setSendingReq] = useState(false);
  const { value: dueDay } = useAppSetting('dueDay', '10');
  const { value: yearlyDiscountPct } = useAppSetting('yearlyDiscountPct', '10');
  const discountPct = Number(yearlyDiscountPct) || 0;

  const rawLinkedIds = userDoc.memberIds || (userDoc.memberId ? [userDoc.memberId] : []);
  const devFallbackIds = userDoc.role === 'developer' && rawLinkedIds.length === 0 && members[0] ? [members[0].id] : [];
  const myLinkedIds = rawLinkedIds.length > 0 ? rawLinkedIds : devFallbackIds;
  const [viewingId, setViewingId] = useState<string>(myLinkedIds[0] || '');

  const orderedTransactions = useMemo(() => sortByNewest(transactions), [transactions]);
  const snapshot = useMemo(() => computeSnapshot(members, orderedTransactions), [members, orderedTransactions]);
  const filteredTransparency = useMemo(() => filterTransactions(orderedTransactions, filter), [orderedTransactions, filter]);
  const filteredIncome = filteredTransparency.filter(t => t.type === 'income').reduce((s, t) => s + t.amount, 0);
  const filteredExpense = filteredTransparency.filter(t => t.type === 'expense').reduce((s, t) => s + t.amount, 0);

  async function addMemberLink(newId: string) {
    if (!userDoc.uid) return;
    const currentIds = userDoc.memberIds || (userDoc.memberId ? [userDoc.memberId] : []);
    if (currentIds.includes(newId)) return;
    const nextIds = [...currentIds, newId];
    try {
      await updateDoc(doc(db, 'users', userDoc.uid), { memberIds: nextIds });
      await writeLog('SELF_LINK', `User menautkan akun ke anggota ID: ${newId}`, userDoc.uid);
      if (!viewingId) setViewingId(newId);
    } catch {
      alert('Gagal menghubungkan data anggota.');
    }
  }

  async function unlinkMember(removeId: string) {
    if (!userDoc.uid || !confirm('Lepas tautan nama ini dari akun Anda?')) return;
    const nextIds = myLinkedIds.filter(id => id !== removeId);
    try {
      await updateDoc(doc(db, 'users', userDoc.uid), { memberIds: nextIds });
      await writeLog('SELF_UNLINK', `User melepaskan tautan anggota ID: ${removeId}`, userDoc.uid);
      if (viewingId === removeId) setViewingId(nextIds[0] || '');
    } catch {
      alert('Gagal melepas data anggota.');
    }
  }

  function getPaymentState(memberId: string) {
    const today = new Date();
    const paidMonths = new Set(
      orderedTransactions
        .filter(t => t.memberId === memberId && t.type === 'income' && t.category === 'iuran')
        .map(t => t.date?.slice(0, 7))
    );

    let advancePaidUntil = '';
    const checkDate = new Date(today.getFullYear(), today.getMonth(), 1);
    while (paidMonths.has(checkDate.toISOString().slice(0, 7))) {
      advancePaidUntil = checkDate.toISOString().slice(0, 7);
      checkDate.setMonth(checkDate.getMonth() + 1);
    }

    const arrears: string[] = [];
    for (let i = 11; i > 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const mk = d.toISOString().slice(0, 7);
      if (!paidMonths.has(mk)) arrears.push(mk);
    }

    const targetMonth = arrears.length > 0 ? arrears[0] : checkDate.toISOString().slice(0, 7);
    return { paidMonths, advancePaidUntil, arrears, targetMonth };
  }

  async function handleSendPaymentRequest() {
    if (!payMethod || !myData) {
      alert('Pilih metode pembayaran terlebih dahulu.');
      return;
    }

    const { targetMonth } = getPaymentState(myData.id);
    const existingPending = requests.find(r => r.memberId === myData.id && r.status === 'pending');
    if (existingPending) {
      alert(`Masih ada pembayaran yang menunggu konfirmasi admin untuk ${existingPending.dueMonth || 'bulan terkait'}.`);
      return;
    }

    setSendingReq(true);

    const isYearly = payType === 'tahunan';
    const monthlyDue = myData.monthlyDue;
    const normalYearly = monthlyDue * 12;
    const discountAmount = Math.round(normalYearly * (discountPct / 100));
    const finalAmount = isYearly ? (normalYearly - discountAmount) : monthlyDue;

    try {
      await addPaymentRequestToDb({
        uid: userDoc.uid,
        memberId: myData.id,
        memberName: myData.name,
        amount: finalAmount,
        dueMonth: targetMonth,
        method: payMethod === 'qris' ? 'QRIS' : 'Tunai',
        paymentType: payType,
      });
      sendNotification(
        isYearly ? 'Pembayaran Tahunan' : 'Permintaan Pembayaran',
        `${myData.name} mengklaim iuran ${isYearly ? 'tahunan' : 'bulanan'} untuk ${targetMonth} via ${payMethod.toUpperCase()}.`
      );
      setPaySheetOpen(false);
      setPayMethod(null);
      setPayType('bulanan');
      alert('Konfirmasi pembayaran berhasil dikirim. Silakan tunggu admin memverifikasi.');
    } catch (error) {
      console.error('Gagal mengirim permintaan pembayaran:', error);
      alert('Gagal mengirim permintaan. Periksa koneksi internet lalu coba lagi.');
    } finally {
      setSendingReq(false);
    }
  }  bad

  if (loading) {
    return (
      <div className="app-shell" style={{ alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ padding: '64px', opacity: 0.6, fontSize: '14px' }}>Memuat data Kasku...</div>
      </div>
    );
  }

  const filteredMembers = members.filter(m => m.name.toLowerCase().includes(searchQuery.toLowerCase()));

  if (myLinkedIds.length === 0 || activeTab === 'add_link') {
    return (
      <div className="app-shell" style={{ padding: '20px', alignItems: 'center' }}>
        <div className="empty-state">
          <strong>Hai, {userDoc.name}</strong>
          <p>
            {myLinkedIds.length === 0
              ? 'Tautkan akun ini dengan nama Anda di buku kas.'
              : 'Cari nama anggota keluarga lain untuk ditambahkan.'}
          </p>
        </div>
        <div className="panel" style={{ width: '100%', maxWidth: '400px', margin: 0, padding: '16px 0' }}>
          <h3 style={{ padding: '0 16px', margin: '0 0 12px', fontSize: '16px' }}>Pilih Nama Anggota:</h3>
          <div style={{ padding: '0 16px', marginBottom: '12px' }}>
            <div style={{ position: 'relative', display: 'flex', alignItems: 'center' }}>
              <Search size={18} color="var(--text-secondary)" style={{ position: 'absolute', left: '16px' }} />
              <input
                className="text-input"
                style={{ paddingLeft: '44px', minHeight: '44px' }}
                placeholder="Cari nama..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <div className="list-stack" style={{ maxHeight: '50vh', overflowY: 'auto' }}>
            {filteredMembers.length === 0 ? (
              <p style={{ padding: '0 16px', fontSize: '14px', color: 'var(--text-secondary)' }}>
                {members.length === 0 ? 'Belum ada data warga di sistem.' : 'Nama tidak ditemukan.'}
              </p>
            ) : filteredMembers.map(member => {
              const isLinked = myLinkedIds.includes(member.id);
              return (
                <article
                  key={member.id}
                  className="list-row"
                  style={{ padding: '12px 16px', cursor: isLinked ? 'default' : 'pointer', borderBottom: '1px solid var(--border)', opacity: isLinked ? 0.5 : 1 }}
                  onClick={() => {
                    if (isLinked) return;
                    if (confirm(`Tautkan "${member.name}" ke akun Anda?`)) {
                      addMemberLink(member.id);
                      setActiveTab('home');
                    }
                  }}
                >
                  <div>
                    <strong>{member.name} {isLinked && '(Tertaut)'}</strong>
                    <small>{member.address || 'Tanpa alamat'}</small>
                  </div>
                </article>
              );
            })}
          </div>
        </div>
        {myLinkedIds.length > 0 ? (
          <button className="secondary-button" onClick={() => setActiveTab('profile')} style={{ marginTop: '24px' }}>Batal</button>
        ) : (
          <button className="secondary-button" onClick={() => auth.signOut()} style={{ marginTop: '24px' }}>Keluar</button>
        )}
      </div>
    );
  }

  const currentViewId = viewingId || myLinkedIds[0];
  const myData = members.find(m => m.id === currentViewId);

  if (!myData) {
    return (
      <div className="app-shell" style={{ padding: 20, alignItems: 'center', justifyContent: 'center' }}>
        <div className="empty-state">
          <strong>Data anggota tidak ditemukan.</strong>
          <p>Data yang tertaut mungkin telah dihapus oleh admin.</p>
          <button className="secondary-button" onClick={() => unlinkMember(currentViewId)} style={{ marginTop: 16 }}>
            Reset Tautan
          </button>
        </div>
      </div>
    );
  }

  const isPaidThisMonth = snapshot.paidMemberIds.includes(myData.id);
  const myTransactions = orderedTransactions.filter(t => t.memberId === myData.id);
  const currentMonth = getCurrentMonthKey();
  const pendingReq = requests.find(r => r.memberId === myData.id && r.status === 'pending' && (!r.dueMonth || r.dueMonth === currentMonth));

  const renderHome = () => {
    const today = new Date();
    const currentMonth = getCurrentMonthKey();

    // Hitung berapa bulan yang sudah dibayar (tanpa batas tahun, bisa jadi sudah bayar advance)
    const myPaidMonths = new Set(
      orderedTransactions
        .filter(t => t.memberId === myData!.id && t.type === 'income' && t.category === 'iuran')
        .map(t => t.date?.slice(0, 7))
    );

    // Cari bulan terakhir yang LUNAS secara berurutan mulai dari bulan ini ke masa depan (Advance payments)
    let advanceLunasBulan = '';
    let checkDate = new Date(today.getFullYear(), today.getMonth(), 1);
    while (myPaidMonths.has(checkDate.toISOString().slice(0, 7))) {
      advanceLunasBulan = checkDate.toISOString().slice(0, 7);
      checkDate.setMonth(checkDate.getMonth() + 1);
    }
    const isPaidThisMonth = advanceLunasBulan !== '';

    // Hitung tunggakan masa lalu (bulan-bulan di bawah bulan ini, dalam 1 tahun terakhir)
    const arrears: string[] = [];
    for (let i = 11; i > 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const mk = d.toISOString().slice(0, 7);
      if (!myPaidMonths.has(mk)) arrears.push(mk);
    }

    // Tentukan tagihan target: Jika ada tunggakan masa lalu, targetnya adalah tunggakan tertua.
    // Jika tidak ada tunggakan, targetnya adalah bulan setelah bulan lunas terakhir.
    let targetMonthStr = '';
    if (arrears.length > 0) {
      targetMonthStr = arrears[0];
    } else {
      targetMonthStr = checkDate.toISOString().slice(0, 7); // Bulan yang gagal loop `while` di atas
    }

    // Formatting UI untuk bulan target
    const [tYear, tMon] = targetMonthStr.split('-');
    const targetDateObj = new Date(Number(tYear), Number(tMon) - 1, 1);
    const targetMonthLabel = targetDateObj.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' });

    // Hitung tanggal jatuh tempo (dueDay) pada bulan target
    const dueDayNum = Math.min(Math.max(Number(dueDay) || 10, 1), 31);
    const dueDate = new Date(Number(tYear), Number(tMon) - 1, dueDayNum);
    
    // Jika jatuh tempo bulan target sudah terlewat DIBANDING HARI INI
    let diffDays = 999;
    if (dueDate.getTime() >= today.getTime()) {
      diffDays = Math.ceil((dueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    } else {
      diffDays = -Math.ceil((today.getTime() - dueDate.getTime()) / (1000 * 60 * 60 * 24)); // Minus artinya telat
    }
    
    const dueDateLabel = dueDate.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });

    // Pending request detection, cari request untuk `targetMonthStr`
    const pendingReqTarget = requests.find(r => r.memberId === myData!.id && r.status === 'pending' && r.dueMonth === targetMonthStr);
    const pendingReqAny = requests.find(r => r.memberId === myData!.id && r.status === 'pending'); // Jika ada pending apapun, kita disable form

    return (
      <div className="view-stack page-stack">
        <section className="panel" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'transparent', border: 'none', padding: '0 16px' }}>
          <div>
            <h2 style={{ margin: 0, fontSize: '20px', fontWeight: 700 }}>Hai, {userDoc.name}</h2>
            <p style={{ margin: '4px 0 0', color: 'var(--text-secondary)', fontSize: '13px' }}>
              Data: <strong>{myData!.name}</strong>
            </p>
          </div>
          {myLinkedIds.length > 1 && (
            <button className="icon-button" onClick={() => setActiveTab('profile')} aria-label="Ganti Profil">
              <UsersRound size={18} />
            </button>
          )}
        </section>

        {/* HERO — STATUS IURAN */}
        <section className="hero-balance">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <span className="eyebrow">Status Iuran {myData!.name}</span>
              <h2>{isPaidThisMonth ? 'LUNAS' : formatCurrency(myData!.monthlyDue)}</h2>
            </div>
            <span className="pill" style={{ background: isPaidThisMonth || pendingReqAny ? 'rgba(255,255,255,0.2)' : '#FFFFFF', color: isPaidThisMonth || pendingReqAny ? '#FFFFFF' : 'var(--accent)' }}>
              {isPaidThisMonth ? 'Lunas' : (pendingReqAny ? 'Diproses' : 'Belum')}
            </span>
          </div>

          <p style={{ marginBottom: '16px' }}>
            {isPaidThisMonth
              ? advanceLunasBulan && advanceLunasBulan > currentMonth 
                  ? `Lunas di muka hingga bulan ${new Date(Number(advanceLunasBulan.split('-')[0]), Number(advanceLunasBulan.split('-')[1]) - 1).toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}.`
                  : 'Terima kasih telah membayar iuran bulan ini.'
              : pendingReqAny
              ? 'Pembayaran Anda sedang menunggu konfirmasi RT.'
              : 'Segera lunasi iuran wajib kas bulanan.'}
          </p>

          {!isPaidThisMonth && !pendingReqAny && (
            <button
              className="secondary-button wide"
              style={{ marginBottom: '16px', background: '#FFFFFF', color: 'var(--text-primary)', border: 'none' }}
              onClick={() => { setPayMethod(null); setPayType('bulanan'); setPaySheetOpen(true); }}
            >
              Bayar Iuran
            </button>
          )}

          <div style={{ borderTop: '1px solid rgba(255,255,255,0.2)', paddingTop: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: '13px', fontWeight: 600, color: '#FFE6DF' }}>Total Kas RT Saat Ini</span>
            <strong style={{ fontSize: '18px', color: '#FFFFFF' }}>{formatCurrency(snapshot.balance)}</strong>
          </div>
        </section>

        {/* TAGIHAN BERIKUTNYA / TARGET BULAN */}
        {!isPaidThisMonth && (
          <section className="panel" style={{ padding: 0, overflow: 'hidden' }}>
            <div style={{ padding: '14px 16px 10px', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h3 style={{ margin: 0, fontSize: 14, fontWeight: 700 }}>Tagihan Berikutnya</h3>
              <span className="pill warning" style={{ fontSize: 11, padding: '2px 8px' }}>Bulan {targetMonthLabel}</span>
            </div>
            <div style={{ padding: '12px 16px 16px', display: 'flex', flexDirection: 'column', gap: 10 }}>
              {/* Jatuh tempo baris */}
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 13, color: 'var(--text-secondary)' }}>Jatuh tempo</span>
                <span style={{ fontSize: 13, fontWeight: 700, color: diffDays < 0 || diffDays <= 3 ? 'var(--danger)' : 'var(--text-primary)' }}>
                  {dueDateLabel} {diffDays < 0 ? '(Terlewat)' : diffDays <= 7 ? `(${diffDays} hari lagi)` : ''}
                </span>
              </div>

              {/* Nominal */}
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 13, color: 'var(--text-secondary)' }}>Nominal iuran</span>
                <span style={{ fontSize: 13, fontWeight: 700 }}>{formatCurrency(myData!.monthlyDue)}</span>
              </div>

              {/* Diskon tahunan */}
              {discountPct > 0 && (
                <div
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    padding: '8px 12px',
                    borderRadius: 'var(--radius-md)',
                    background: 'var(--success-soft)',
                    marginTop: 4,
                  }}
                >
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    <Tag size={13} color="var(--success)" />
                    <span style={{ fontSize: 12, color: 'var(--success)', fontWeight: 600 }}>
                      Bayar tahunan, hemat {discountPct}%!
                    </span>
                  </div>
                  <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--success)' }}>
                    {formatCurrency(myData!.monthlyDue * 12 * (1 - discountPct / 100))} / thn
                  </span>
                </div>
              )}

              {/* Tunggakan peringatan */}
              {arrears.length > 0 && (
                <div style={{ padding: '8px 12px', borderRadius: 'var(--radius-md)', background: 'var(--danger-soft)', marginTop: 4 }}>
                  <span style={{ fontSize: 12, color: 'var(--danger)', fontWeight: 600 }}>
                    ⚠ Ada {arrears.length} bulan tunggakan masa lalu
                  </span>
                </div>
              )}

              {/* CTA tahunan */}
              {!pendingReqAny && discountPct > 0 && (
                <button
                  className="secondary-button wide"
                  style={{ marginTop: 4 }}
                  onClick={() => { setPayType('tahunan'); setPayMethod(null); setPaySheetOpen(true); }}
                >
                  <Tag size={16} /> Bayar 1 Tahun Penuh
                </button>
              )}
            </div>
          </section>
        )}

        {/* RIWAYAT TRANSAKSI SAYA */}
        {myTransactions.length > 0 && (
          <section className="panel">
            <div className="panel-heading">
              <div><h3>Riwayat Saya</h3><p>Histori pembayaran iuran atas nama {myData!.name}.</p></div>
            </div>
            <div className="list-stack">
              {myTransactions.slice(0, 5).map(item => (
                <article className="list-row tall" key={item.id}>
                  <div style={{ display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                    <div className="action-icon" style={{ width: 36, height: 36, borderRadius: 12 }}>
                      <ArrowDownCircle size={18} />
                    </div>
                    <div>
                      <strong>{item.note || item.category}</strong>
                      <small>{new Date(item.date).toLocaleDateString('id-ID')}</small>
                    </div>
                  </div>
                  <div className="amount-display success">
                    <strong>+ {formatCurrency(item.amount)}</strong>
                  </div>
                </article>
              ))}
            </div>
          </section>
        )}
      </div>
    );
  };

  const renderTransparency = () => (
    <div className="view-stack page-stack">
      <section className="panel compact-gap">
        <div className="panel-heading">
          <div><h3>Transparansi Kas</h3><p>Semua pemasukan dan pengeluaran RT.</p></div>
        </div>
        <div className="segmented-tabs" style={{ marginBottom: 0 }}>
          {DATE_FILTERS.map(({ value: val, label: lbl }) => (
            <button
              key={val}
              type="button"
              className={`segment ${filter === val ? 'is-active' : ''}`}
              onClick={() => setFilter(val)}
            >
              {lbl}
            </button>
          ))}
        </div>
      </section>

      <div className="metric-grid">
        <article className="metric-card">
          <span>Pemasukan</span>
          <strong style={{ color: 'var(--success)' }}>{formatCurrency(filteredIncome)}</strong>
        </article>
        <article className="metric-card">
          <span>Pengeluaran</span>
          <strong style={{ color: 'var(--danger)' }}>{formatCurrency(filteredExpense)}</strong>
        </article>
      </div>

      <section className="panel">
        {filteredTransparency.length > 0 ? (
          <div className="list-stack">
            {filteredTransparency.map(item => (
              <article className="list-row tall" key={item.id}>
                <div style={{ display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                  <div className="action-icon" style={{ width: 36, height: 36, borderRadius: 12, background: item.type === 'income' ? 'var(--success-soft)' : 'var(--danger-soft)', color: item.type === 'income' ? 'var(--success)' : 'var(--danger)' }}>
                    {item.type === 'income' ? <ArrowDownCircle size={18} /> : <ArrowUpCircle size={18} />}
                  </div>
                  <div>
                    <strong>{item.note || item.category}</strong>
                    <small>{new Date(item.date).toLocaleDateString('id-ID')} - {item.category}</small>
                  </div>
                </div>
                <div className={`amount-display ${item.type === 'income' ? 'success' : 'danger'}`}>
                  <strong>{item.type === 'income' ? '+' : '-'} {formatCurrency(item.amount)}</strong>
                </div>
              </article>
            ))}
          </div>
        ) : (
          <div className="empty-state">
            <strong>Tidak ada transaksi.</strong>
            <p>Belum ada data untuk rentang waktu ini.</p>
          </div>
        )}
      </section>
    </div>
  );

  const renderProfile = () => (
    <div className="view-stack page-stack">
      <section className="panel">
        <div className="panel-heading">
          <div><h3>Akun Saya</h3><p>{userDoc.name}</p></div>
          <UserRound size={20} color="var(--text-secondary)" />
        </div>
        <div className="list-stack">
          {myLinkedIds.map(id => {
            const m = members.find(x => x.id === id);
            if (!m) return null;
            return (
              <article className="list-row" key={id}>
                <div>
                  <strong>{m.name}</strong>
                  <small>{m.address || 'Tanpa alamat'}</small>
                </div>
                <div style={{ display: 'flex', gap: 8 }}>
                  {myLinkedIds.length > 1 && (
                    <button
                      className="icon-button"
                      style={{ background: 'var(--danger-soft)', color: 'var(--danger)' }}
                      onClick={() => unlinkMember(id)}
                      aria-label="Lepas tautan"
                    >
                      <UserPlus size={16} />
                    </button>
                  )}
                  <button
                    className={`icon-button ${viewingId === id ? 'is-active' : ''}`}
                    onClick={() => { setViewingId(id); setActiveTab('home'); }}
                    aria-label="Lihat data ini"
                  >
                    <Home size={16} />
                  </button>
                </div>
              </article>
            );
          })}
        </div>
        <button
          className="secondary-button wide"
          style={{ marginTop: 16 }}
          onClick={() => setActiveTab('add_link')}
        >
          <UserPlus size={18} /> Tambah Anggota Keluarga
        </button>
        <button
          className="secondary-button wide"
          style={{ marginTop: 12, color: 'var(--danger)' }}
          onClick={() => auth.signOut()}
        >
          <LogOut size={18} /> Keluar
        </button>
      </section>
    </div>
  );

  const NAV_TABS: { id: WargaTab; label: string; icon: React.ReactNode }[] = [
    { id: 'home', label: 'Beranda', icon: <Home size={20} /> },
    { id: 'transparency', label: 'Kas', icon: <ChartNoAxesColumnIncreasing size={20} /> },
    { id: 'profile', label: 'Profil', icon: <UserRound size={20} /> },
  ];

  return (
    <div className="app-shell">
      <main className="content-scroll">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'transparency' && renderTransparency()}
        {activeTab === 'profile' && renderProfile()}
      </main>

      <nav className="bottom-bar" aria-label="Navigasi warga">
        {NAV_TABS.map(tab => (
          <button
            key={tab.id}
            className={`tab-button${activeTab === tab.id ? ' is-active' : ''}`}
            onClick={() => setActiveTab(tab.id)}
            type="button"
          >
            {tab.icon}
            <span>{tab.label}</span>
          </button>
        ))}
      </nav>

      <Sheet
        open={paySheetOpen}
        onClose={() => { setPaySheetOpen(false); setPayMethod(null); setPayType('bulanan'); }}
        title={payType === 'tahunan' ? 'Bayar Iuran Tahunan' : 'Bayar Iuran Bulanan'}
        subtitle={
          payType === 'tahunan'
            ? `Total bayar ${formatCurrency(myData.monthlyDue * 12 * (1 - discountPct / 100))} (setelah diskon ${discountPct}%).`
            : `Iuran ${myData.name} sebesar ${formatCurrency(myData.monthlyDue)}.`
        }
      >
        <div className="form-stack">
          {payType === 'tahunan' && (
            <div
              className="panel"
              style={{ margin: 0, background: 'var(--success-soft)', border: 'none', padding: 14 }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                <Tag size={16} color="var(--success)" />
                <strong style={{ fontSize: 14, color: 'var(--success)' }}>Paket Iuran Tahunan</strong>
              </div>
              <div style={{ display: 'grid', gap: 6, fontSize: 13 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span>Total normal</span>
                  <strong>{formatCurrency(myData.monthlyDue * 12)}</strong>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: 'var(--success)' }}>
                  <span>Diskon {discountPct}%</span>
                  <strong>- {formatCurrency(myData.monthlyDue * 12 * (discountPct / 100))}</strong>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', borderTop: '1px solid var(--border)', paddingTop: 6 }}>
                  <span>Bayar sekarang</span>
                  <strong>{formatCurrency(myData.monthlyDue * 12 * (1 - discountPct / 100))}</strong>
                </div>
              </div>
            </div>
          )}

          <PremiumDropdown
            label="Metode Pembayaran"
            value={payMethod ?? ''}
            options={PAYMENT_METHODS}
            onChange={v => setPayMethod(v as 'qris' | 'tunai')}
            placeholder="Pilih metode"
          />

          {payMethod === 'qris' && (
            <div className="panel" style={{ margin: 0, textAlign: 'center', background: 'var(--surface-2)', border: 'none' }}>
              <QrCode size={64} color="var(--text-secondary)" style={{ margin: '8px auto' }} />
              <p style={{ margin: '8px 0 0', fontSize: '13px', color: 'var(--text-secondary)', lineHeight: 1.5 }}>
                Scan QRIS dari aplikasi dompet digital Anda, lalu tekan konfirmasi.
              </p>
            </div>
          )}

          {payMethod === 'tunai' && (
            <div className="panel" style={{ margin: 0, background: 'var(--surface-2)', border: 'none' }}>
              <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
                <MessageCircle size={20} color="var(--text-secondary)" />
                <p style={{ margin: 0, fontSize: '13px', color: 'var(--text-secondary)', lineHeight: 1.5 }}>
                  Siapkan uang tunai dan serahkan langsung ke petugas kas. Konfirmasi akan dikirim oleh admin.
                </p>
              </div>
            </div>
          )}

          <button
            className="primary-button wide"
            onClick={handleSendPaymentRequest}
            disabled={!payMethod || sendingReq}
            type="button"
          >
            <Receipt size={18} />
            {sendingReq ? 'Mengirim...' : 'Kirim Konfirmasi'}
          </button>
        </div>
      </Sheet>
    </div>
  );
}
